  1→package item
  2→
  3→import (
  4→	"fmt"
  5→	"strings"
  6→)
  7→
  8→// queryBuilder constructs a dynamic WHERE clause with parameterized conditions.
  9→type queryBuilder struct {
 10→	conditions []string
 11→	args       []any
 12→}
 13→
 14→// add appends a condition with a single parameter. Use %d as the placeholder
 15→// position in the condition template (e.g., "type = $%d").
 16→func (qb *queryBuilder) add(conditionTemplate string, arg any) {
 17→	qb.args = append(qb.args, arg)
 18→	qb.conditions = append(qb.conditions, fmt.Sprintf(conditionTemplate, len(qb.args)))
 19→}
 20→
 21→// where returns the WHERE clause string (including "WHERE") or empty string if
 22→// no conditions were added.
 23→func (qb *queryBuilder) where() string {
 24→	if len(qb.conditions) == 0 {
 25→		return ""
 26→	}
 27→	return "WHERE " + strings.Join(qb.conditions, " AND ")
 28→}
 29→
 30→// nextParam returns the next parameter placeholder number without adding a condition.
 31→func (qb *queryBuilder) nextParam() int {
 32→	return len(qb.args) + 1
 33→}
 34→
 35→// sortFieldToColumn maps GraphQL sort field names to database column names.
 36→// Returns the column name and true if valid, or empty string and false if not.
 37→func sortFieldToColumn(field string) (string, bool) {
 38→	switch strings.ToUpper(field) {
 39→	case "CREATED_AT":
 40→		return "created_at", true
 41→	case "UPDATED_AT":
 42→		return "updated_at", true
 43→	case "CAPTURED_AT":
 44→		return "captured_at", true
 45→	case "TITLE":
 46→		return "title", true
 47→	default:
 48→		return "", false
 49→	}
 50→}
 51→
 52→// sortDirectionSQL returns "ASC" or "DESC". Defaults to "DESC" for invalid input.
 53→func sortDirectionSQL(dir string) string {
 54→	if strings.ToUpper(dir) == "ASC" {
 55→		return "ASC"
 56→	}
 57→	return "DESC"
 58→}
 59→
 60→// applyFilter adds filter conditions to the query builder.
 61→func applyFilter(qb *queryBuilder, f *Filter) {
 62→	if f == nil {
 63→		return
 64→	}
 65→	if len(f.Types) == 1 {
 66→		qb.add("type = $%d", f.Types[0])
 67→	} else if len(f.Types) > 1 {
 68→		qb.add("type = ANY($%d)", f.Types)
 69→	}
 70→	if len(f.Status) == 1 {
 71→		qb.add("status = $%d", f.Status[0])
 72→	} else if len(f.Status) > 1 {
 73→		qb.add("status = ANY($%d)", f.Status)
 74→	}
 75→	if len(f.Sensitivity) == 1 {
 76→		qb.add("sensitivity = $%d", f.Sensitivity[0])
 77→	} else if len(f.Sensitivity) > 1 {
 78→		qb.add("sensitivity = ANY($%d)", f.Sensitivity)
 79→	}
 80→	if len(f.Tags) > 0 {
 81→		qb.add("tags && $%d", f.Tags)
 82→	}
 83→	if f.Source != nil {
 84→		qb.add("source = $%d", *f.Source)
 85→	}
 86→	if f.DateFrom != nil {
 87→		qb.add("created_at >= $%d", *f.DateFrom)
 88→	}
 89→	if f.DateTo != nil {
 90→		qb.add("created_at <= $%d", *f.DateTo)
 91→	}
 92→}
 93→
 94→// clampLimit ensures limit is between 1 and maxLimit.
 95→func clampLimit(limit, maxLimit int) int {
 96→	if limit <= 0 {
 97→		return 20
 98→	}
 99→	if limit > maxLimit {
100→		return maxLimit
101→	}
102→	return limit
103→}
104→
105→// clampOffset ensures offset is non-negative.
106→func clampOffset(offset int) int {
107→	if offset < 0 {
108→		return 0
109→	}
110→	return offset
111→}
