137→// CaptureBookmark creates a new bookmark item.
138→func (s *Service) CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input BookmarkInput) (*Item, error) {
139→	if input.URL == "" {
140→		return nil, fmt.Errorf("item: capture bookmark: url is required")
141→	}
142→	if input.Source == "" {
143→		input.Source = "api"
144→	}
145→	if input.Sensitivity == "" {
146→		input.Sensitivity = "normal"
147→	}
148→
149→	tags := input.Tags
150→	if tags == nil {
151→		tags = []string{}
152→	}
153→
154→	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_url, tags, source, metadata, auto_metadata)
155→		VALUES ($1, 'bookmark', 'pending', $2, $3, $4, $5, $6, '{}', '{}')
156→		RETURNING %s`, itemColumns)
157→
158→	row := s.pool.QueryRow(ctx, query,
159→		ownerID, input.Sensitivity, input.Title, input.URL, tags, input.Source)
160→
161→	it, err := scanItem(row)
162→	if err != nil {
163→		return nil, fmt.Errorf("item: capture bookmark: %w", err)
164→	}
165→	return it, nil
166→}
