236→// Update partially updates an item. Only non-nil fields in input are changed.
237→func (s *Service) Update(ctx context.Context, ownerID, itemID uuid.UUID, input UpdateInput) (*Item, error) {
238→	sets := []string{}
239→	args := []any{ownerID, itemID}
240→	paramIdx := 3
241→
242→	if input.Title != nil {
243→		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
244→		args = append(args, *input.Title)
245→		paramIdx++
246→	}
247→	if input.Tags != nil {
248→		sets = append(sets, fmt.Sprintf("tags = $%d", paramIdx))
249→		args = append(args, input.Tags)
250→		paramIdx++
251→	}
252→	if input.Sensitivity != nil {
253→		sets = append(sets, fmt.Sprintf("sensitivity = $%d", paramIdx))
254→		args = append(args, *input.Sensitivity)
255→		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
256→	}
257→
258→	if len(sets) == 0 {
259→		return s.GetByID(ctx, ownerID, itemID)
260→	}
261→
262→	query := fmt.Sprintf(`UPDATE items SET %s WHERE owner_id = $1 AND id = $2 RETURNING %s`,
263→		joinSets(sets), itemColumns)
264→
265→	row := s.pool.QueryRow(ctx, query, args...)
266→	it, err := scanItem(row)
267→	if errors.Is(err, pgx.ErrNoRows) {
268→		return nil, fmt.Errorf("item: update: not found")
269→	}
270→	if err != nil {
271→		return nil, fmt.Errorf("item: update: %w", err)
272→	}
273→	return it, nil
274→}
