276→// Delete removes an item by ID and owner. Returns an error if not found.
277→func (s *Service) Delete(ctx context.Context, ownerID, itemID uuid.UUID) error {
278→	tag, err := s.pool.Exec(ctx,
279→		"DELETE FROM items WHERE owner_id = $1 AND id = $2",
280→		ownerID, itemID)
281→	if err != nil {
282→		return fmt.Errorf("item: delete: %w", err)
283→	}
284→	if tag.RowsAffected() == 0 {
285→		return fmt.Errorf("item: delete: not found")
286→	}
287→	return nil
288→}
