 52→func (w *PageFetchWorker) Work(ctx context.Context, job *river.Job[PageFetchArgs]) error {
 53→	itemID := job.Args.ItemID
 54→	url := job.Args.URL
 55→
 56→	slog.InfoContext(ctx, "worker: page_fetch: processing",
 57→		"item_id", itemID,
 58→		"url", url,
 59→	)
 60→
 61→	// Mark item as processing
 62→	if err := w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "processing"}); err != nil {
 63→		return fmt.Errorf("worker: page_fetch: set processing: %w", err)
 64→	}
 65→
 66→	// Fetch and extract content
 67→	article, err := w.fetchAndExtract(ctx, url)
 68→	if err != nil {
 69→		// Set item to error status
 70→		_ = w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "error"})
 71→		return fmt.Errorf("worker: page_fetch: fetch: %w", err)
 72→	}
 73→
 74→	// Upload HTML to S3 if storage is configured
 75→	var contentURL *string
 76→	if w.Storage != nil && article.Content != "" {
 77→		key := fmt.Sprintf("items/%s/page.html", itemID)
 78→		if err := w.Storage.Upload(ctx, key, strings.NewReader(article.Content), "text/html"); err != nil {
 79→			slog.ErrorContext(ctx, "worker: page_fetch: s3 upload failed, continuing without",
 80→				"item_id", itemID,
 81→				"error", err,
 82→			)
 83→		} else {
 84→			contentURL = &key
 85→		}
 86→	}
 87→
 88→	// Build content update
 89→	update := item.ContentUpdate{Status: "ready"}
 90→	if article.Title != "" {
 91→		update.Title = &article.Title
 92→	}
 93→	if article.TextContent != "" {
 94→		update.ContentText = &article.TextContent
 95→	}
 96→	if contentURL != nil {
 97→		update.ContentURL = contentURL
 98→	}
 99→
100→	if err := w.Items.UpdateContent(ctx, itemID, update); err != nil {
101→		return fmt.Errorf("worker: page_fetch: update item: %w", err)
102→	}
103→
104→	slog.InfoContext(ctx, "worker: page_fetch: done",
105→		"item_id", itemID,
106→		"title", article.Title,
107→		"text_length", len(article.TextContent),
108→	)
109→	return nil
110→}
