112→type fetchResult struct {
113→	Title       string
114→	TextContent string
115→	Content     string // HTML content
116→}
117→
118→func (w *PageFetchWorker) fetchAndExtract(ctx context.Context, url string) (*fetchResult, error) {
119→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
120→	if err != nil {
121→		return nil, fmt.Errorf("build request: %w", err)
122→	}
123→	req.Header.Set("User-Agent", userAgent)
124→
125→	resp, err := w.httpClient().Do(req)
126→	if err != nil {
127→		return nil, fmt.Errorf("http get: %w", err)
128→	}
129→	defer func() { _ = resp.Body.Close() }()
130→
131→	if resp.StatusCode >= 400 {
132→		return nil, fmt.Errorf("http status %d for %s", resp.StatusCode, url)
133→	}
134→
135→	article, err := readability.FromReader(resp.Body, nil)
136→	if err != nil {
137→		return nil, fmt.Errorf("readability parse: %w", err)
138→	}
139→
140→	return &fetchResult{
141→		Title:       article.Title,
142→		TextContent: article.TextContent,
143→		Content:     article.Content,
144→	}, nil
145→}
