201→// Item is the resolver for the item field.
202→func (r *queryResolver) Item(ctx context.Context, id string) (*model.Item, error) {
203→	claims, err := requireAuth(ctx)
204→	if err != nil {
205→		return nil, err
206→	}
207→
208→	itemID, err := uuid.Parse(id)
209→	if err != nil {
210→		return nil, fmt.Errorf("resolver: invalid item id: %w", err)
211→	}
212→
213→	it, err := r.ItemService.GetByID(ctx, claims.UserID, itemID)
214→	if err != nil {
215→		return nil, fmt.Errorf("resolver: item: %w", err)
216→	}
217→	if it == nil {
218→		return nil, nil
219→	}
220→	return toGraphQLItem(it), nil
221→}
