223→// Items is the resolver for the items field.
224→func (r *queryResolver) Items(ctx context.Context, filter *model.ItemFilter, limit *int, offset *int, sort *model.ItemSort) (*model.SearchResult, error) {
225→	claims, err := requireAuth(ctx)
226→	if err != nil {
227→		return nil, err
228→	}
229→
230→	result, err := r.ItemService.List(ctx, claims.UserID,
231→		toItemFilter(filter),
232→		derefIntOr(limit, 20),
233→		derefIntOr(offset, 0),
234→		toItemSort(sort))
235→	if err != nil {
236→		return nil, fmt.Errorf("resolver: items: %w", err)
237→	}
238→
239→	return &model.SearchResult{
240→		Items:   toGraphQLItems(result.Items),
241→		Total:   result.Total,
242→		HasMore: result.HasMore,
243→	}, nil
244→}
