246→// Search is the resolver for the search field.
247→func (r *queryResolver) Search(ctx context.Context, query string, filter *model.ItemFilter, limit *int, threshold *float64) (*model.SearchResult, error) {
248→	claims, err := requireAuth(ctx)
249→	if err != nil {
250→		return nil, err
251→	}
252→
253→	result, err := r.ItemService.Search(ctx, claims.UserID, query,
254→		toItemFilter(filter),
255→		derefIntOr(limit, 20),
256→		derefFloat64Or(threshold, 0.0))
257→	if err != nil {
258→		return nil, fmt.Errorf("resolver: search: %w", err)
259→	}
260→
261→	return &model.SearchResult{
262→		Items:   toGraphQLItems(result.Items),
263→		Total:   result.Total,
264→		HasMore: result.HasMore,
265→	}, nil
266→}
