 2→
 3→import (
 4→	"bytes"
 5→	"context"
 6→	"fmt"
 7→	"io"
 8→	"os"
 9→	"os/exec"
10→	"path/filepath"
11→	"strings"
12→)
13→
14→// WhisperLocalProvider transcribes audio using a local whisper.cpp binary.
15→type WhisperLocalProvider struct {
16→	binaryPath string
17→	modelPath  string
18→}
19→
20→// NewWhisperLocal creates a WhisperLocalProvider.
21→func NewWhisperLocal(binaryPath, modelPath string) *WhisperLocalProvider {
22→	return &WhisperLocalProvider{
23→		binaryPath: binaryPath,
24→		modelPath:  modelPath,
25→	}
26→}
27→
28→// Transcribe writes audio to a temp file, runs whisper.cpp, and returns the transcript.
29→func (p *WhisperLocalProvider) Transcribe(ctx context.Context, audio io.Reader, opts TranscribeOpts) (string, error) {
30→	ext := "wav"
31→	if opts.Format != "" {
32→		ext = opts.Format
33→	}
34→
35→	tmpFile, err := os.CreateTemp("", "whisper-*."+ext)
36→	if err != nil {
37→		return "", fmt.Errorf("provider: whisper local: create temp file: %w", err)
38→	}
39→	tmpPath := tmpFile.Name()
40→	defer func() { _ = os.Remove(tmpPath) }()
41→
42→	if _, err := io.Copy(tmpFile, audio); err != nil {
43→		_ = tmpFile.Close()
44→		return "", fmt.Errorf("provider: whisper local: write temp file: %w", err)
45→	}
46→	_ = tmpFile.Close()
47→
48→	args := []string{
49→		"-m", p.modelPath,
50→		"-f", tmpPath,
51→		"--no-timestamps",
52→		"--output-txt",
53→	}
54→	if opts.Language != "" {
55→		args = append(args, "-l", opts.Language)
56→	}
57→
58→	cmd := exec.CommandContext(ctx, p.binaryPath, args...)
59→	var stdout, stderr bytes.Buffer
60→	cmd.Stdout = &stdout
61→	cmd.Stderr = &stderr
62→
63→	if err := cmd.Run(); err != nil {
64→		return "", fmt.Errorf("provider: whisper local: exec: %w: %s", err, stderr.String())
65→	}
66→
67→	// whisper.cpp with --output-txt writes to <input>.txt
68→	txtPath := tmpPath + ".txt"
69→	if _, err := os.Stat(txtPath); err == nil {
70→		defer func() { _ = os.Remove(txtPath) }()
71→		data, err := os.ReadFile(filepath.Clean(txtPath))
72→		if err != nil {
73→			return "", fmt.Errorf("provider: whisper local: read output: %w", err)
74→		}
75→		text := strings.TrimSpace(string(data))
76→		if text == "" {
77→			return "", fmt.Errorf("provider: whisper local: empty transcript")
78→		}
79→		return text, nil
80→	}
81→
82→	// fallback: some versions write to stdout
83→	text := strings.TrimSpace(stdout.String())
84→	if text == "" {
85→		return "", fmt.Errorf("provider: whisper local: empty transcript")
86→	}
87→	return text, nil
88→}
