329→// UpdateContent updates worker-managed fields (status, title, content) on an item.
330→// This is used by background jobs, not exposed via GraphQL.
331→func (s *Service) UpdateContent(ctx context.Context, itemID uuid.UUID, input ContentUpdate) error {
332→	sets := []string{fmt.Sprintf("status = $%d", 2)}
333→	args := []any{itemID, input.Status}
334→	paramIdx := 3
335→
336→	if input.Title != nil {
337→		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
338→		args = append(args, *input.Title)
339→		paramIdx++
340→	}
341→	if input.ContentText != nil {
342→		sets = append(sets, fmt.Sprintf("content_text = $%d", paramIdx))
343→		args = append(args, *input.ContentText)
344→		paramIdx++
345→	}
346→	if input.ContentURL != nil {
347→		sets = append(sets, fmt.Sprintf("content_url = $%d", paramIdx))
348→		args = append(args, *input.ContentURL)
349→		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
350→	}
351→
352→	query := fmt.Sprintf(`UPDATE items SET %s WHERE id = $1`, joinSets(sets))
353→	tag, err := s.pool.Exec(ctx, query, args...)
354→	if err != nil {
355→		return fmt.Errorf("item: update content: %w", err)
356→	}
357→	if tag.RowsAffected() == 0 {
358→		return fmt.Errorf("item: update content: not found")
359→	}
360→	return nil
361→}
362→
363→func joinSets(sets []string) string {
364→	result := ""
365→	for i, s := range sets {
366→		if i > 0 {
367→			result += ", "
368→		}
369→		result += s
370→	}
371→	return result
372→}
