package worker

import (
	"context"
	"fmt"
	"log/slog"
	"net/http"
	"strings"
	"time"

	readability "github.com/go-shiori/go-readability"
	"github.com/google/uuid"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/item"
	"github.com/ketang/flotsam/api/internal/storage"
)

// ItemContentUpdater updates worker-managed fields on items.
type ItemContentUpdater interface {
	UpdateContent(ctx context.Context, itemID uuid.UUID, input item.ContentUpdate) error
}

const (
	fetchTimeout = 30 * time.Second
	userAgent    = "Flotsam/1.0 (bookmark fetcher)"
)

// PageFetchArgs are the arguments for a page fetch job.
type PageFetchArgs struct {
	ItemID uuid.UUID `json:"item_id"`
	URL    string    `json:"url"`
}

func (PageFetchArgs) Kind() string { return "page_fetch" }

// PageFetchWorker fetches and extracts readable content from bookmark URLs.
type PageFetchWorker struct {
	river.WorkerDefaults[PageFetchArgs]
	Items   ItemContentUpdater
	Storage *storage.Client // nil if S3 not configured
	Client  *http.Client    // nil uses a default client with timeout
}

func (w *PageFetchWorker) httpClient() *http.Client {
	if w.Client != nil {
		return w.Client
	}
	return &http.Client{Timeout: fetchTimeout}
}

func (w *PageFetchWorker) Work(ctx context.Context, job *river.Job[PageFetchArgs]) error {
	itemID := job.Args.ItemID
	url := job.Args.URL

	slog.InfoContext(ctx, "worker: page_fetch: processing",
		"item_id", itemID,
		"url", url,
	)

	// Mark item as processing
	if err := w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "processing"}); err != nil {
		return fmt.Errorf("worker: page_fetch: set processing: %w", err)
	}

	// Fetch and extract content
	article, err := w.fetchAndExtract(ctx, url)
	if err != nil {
		// Set item to error status
		_ = w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "error"})
		return fmt.Errorf("worker: page_fetch: fetch: %w", err)
	}

	// Upload HTML to S3 if storage is configured
	var contentURL *string
	if w.Storage != nil && article.Content != "" {
		key := fmt.Sprintf("items/%s/page.html", itemID)
		if err := w.Storage.Upload(ctx, key, strings.NewReader(article.Content), "text/html"); err != nil {
			slog.ErrorContext(ctx, "worker: page_fetch: s3 upload failed, continuing without",
				"item_id", itemID,
				"error", err,
			)
		} else {
			contentURL = &key
		}
	}

	// Build content update
	update := item.ContentUpdate{Status: "ready"}
	if article.Title != "" {
		update.Title = &article.Title
	}
	if article.TextContent != "" {
		update.ContentText = &article.TextContent
	}
	if contentURL != nil {
		update.ContentURL = contentURL
	}

	if err := w.Items.UpdateContent(ctx, itemID, update); err != nil {
		return fmt.Errorf("worker: page_fetch: update item: %w", err)
	}

	slog.InfoContext(ctx, "worker: page_fetch: done",
		"item_id", itemID,
		"title", article.Title,
		"text_length", len(article.TextContent),
	)
	return nil
}

type fetchResult struct {
	Title       string
	TextContent string
	Content     string // HTML content
}

func (w *PageFetchWorker) fetchAndExtract(ctx context.Context, url string) (*fetchResult, error) {
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, fmt.Errorf("build request: %w", err)
	}
	req.Header.Set("User-Agent", userAgent)

	resp, err := w.httpClient().Do(req)
	if err != nil {
		return nil, fmt.Errorf("http get: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	if resp.StatusCode >= 400 {
		return nil, fmt.Errorf("http status %d for %s", resp.StatusCode, url)
	}

	article, err := readability.FromReader(resp.Body, nil)
	if err != nil {
		return nil, fmt.Errorf("readability parse: %w", err)
	}

	return &fetchResult{
		Title:       article.Title,
		TextContent: article.TextContent,
		Content:     article.Content,
	}, nil
}

package worker

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"path/filepath"
	"strings"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/ketang/flotsam/api/internal/storage"
)

// TranscribeArgs are the arguments for a transcription job.
type TranscribeArgs struct {
	ItemID   uuid.UUID `json:"item_id"`
	OwnerID  uuid.UUID `json:"owner_id"`
	AudioKey string    `json:"audio_key"`
}

func (TranscribeArgs) Kind() string { return "transcribe" }

// TranscribeWorker transcribes audio via Whisper API or local whisper.cpp.
type TranscribeWorker struct {
	river.WorkerDefaults[TranscribeArgs]
	Storage     *storage.Client
	Transcriber provider.Transcriber
	Pool        *pgxpool.Pool
}

func (w *TranscribeWorker) Work(ctx context.Context, job *river.Job[TranscribeArgs]) error {
	slog.InfoContext(ctx, "worker: transcribe: processing",
		"item_id", job.Args.ItemID,
		"audio_key", job.Args.AudioKey,
	)

	if w.Storage == nil {
		return fmt.Errorf("worker: transcribe: storage not configured")
	}
	if w.Transcriber == nil {
		return fmt.Errorf("worker: transcribe: transcriber not configured")
	}

	// Update item status to processing
	if err := w.updateStatus(ctx, job.Args.ItemID, job.Args.OwnerID, "processing", nil); err != nil {
		return fmt.Errorf("worker: transcribe: set processing: %w", err)
	}

	// Download audio from S3
	reader, err := w.Storage.Download(ctx, job.Args.AudioKey)
	if err != nil {
		w.setError(ctx, job.Args.ItemID, job.Args.OwnerID, "failed to download audio")
		return fmt.Errorf("worker: transcribe: download audio: %w", err)
	}
	defer func() { _ = reader.Close() }()

	// Determine format from key extension
	ext := strings.TrimPrefix(filepath.Ext(job.Args.AudioKey), ".")
	if ext == "" {
		ext = "wav"
	}

	// Transcribe
	transcript, err := w.Transcriber.Transcribe(ctx, reader, provider.TranscribeOpts{
		Format: ext,
	})
	if err != nil {
		w.setError(ctx, job.Args.ItemID, job.Args.OwnerID, "transcription failed")
		return fmt.Errorf("worker: transcribe: transcribe: %w", err)
	}

	// Update item with transcript
	_, err = w.Pool.Exec(ctx,
		`UPDATE items SET content_text = $1, status = 'ready', updated_at = now()
		 WHERE id = $2 AND owner_id = $3`,
		transcript, job.Args.ItemID, job.Args.OwnerID)
	if err != nil {
		return fmt.Errorf("worker: transcribe: update item: %w", err)
	}

	slog.InfoContext(ctx, "worker: transcribe: completed",
		"item_id", job.Args.ItemID,
		"transcript_len", len(transcript),
	)
	return nil
}

// updateStatus sets the item's status and optionally stores an error in metadata.
func (w *TranscribeWorker) updateStatus(ctx context.Context, itemID, ownerID uuid.UUID, status string, errMsg *string) error {
	if errMsg != nil {
		meta := map[string]any{"error": *errMsg}
		metaJSON, err := json.Marshal(meta)
		if err != nil {
			return fmt.Errorf("worker: transcribe: marshal error metadata: %w", err)
		}
		_, err = w.Pool.Exec(ctx,
			`UPDATE items SET status = $1, metadata = metadata || $4::jsonb, updated_at = now()
			 WHERE id = $2 AND owner_id = $3`,
			status, itemID, ownerID, metaJSON)
		return err
	}
	_, err := w.Pool.Exec(ctx,
		`UPDATE items SET status = $1, updated_at = now() WHERE id = $2 AND owner_id = $3`,
		status, itemID, ownerID)
	return err
}

// setError is a convenience method that sets the item status to "error".
func (w *TranscribeWorker) setError(ctx context.Context, itemID, ownerID uuid.UUID, msg string) {
	if err := w.updateStatus(ctx, itemID, ownerID, "error", &msg); err != nil {
		slog.ErrorContext(ctx, "worker: transcribe: failed to set error status",
			"item_id", itemID,
			"error", err,
		)
	}
}

package provider

import (
	"context"
	"io"
)

// TranscribeOpts holds options for a transcription request.
type TranscribeOpts struct {
	Language string // BCP-47 language code, e.g. "en"
	Format   string // audio format hint: "wav", "mp3", "webm", "m4a", "ogg", "mp4", "flac"
}

// Transcriber transcribes audio to text.
type Transcriber interface {
	Transcribe(ctx context.Context, audio io.Reader, opts TranscribeOpts) (string, error)
}

