package provider

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
)

const (
	defaultEmbeddingModel   = "text-embedding-3-small"
	defaultEmbeddingBaseURL = "https://api.openai.com/v1"
	defaultEmbeddingDims    = 1536
	maxContentChars         = 30000
)

// OpenAIEmbeddingProvider generates embeddings via the OpenAI API.
type OpenAIEmbeddingProvider struct {
	apiKey     string
	model      string
	baseURL    string
	dimensions int
	client     *http.Client
}

// NewOpenAIEmbedding creates an OpenAIEmbeddingProvider with the given API key.
func NewOpenAIEmbedding(apiKey string, opts ...OpenAIEmbeddingOption) *OpenAIEmbeddingProvider {
	p := &OpenAIEmbeddingProvider{
		apiKey:     apiKey,
		model:      defaultEmbeddingModel,
		baseURL:    defaultEmbeddingBaseURL,
		dimensions: defaultEmbeddingDims,
		client:     http.DefaultClient,
	}
	for _, o := range opts {
		o(p)
	}
	return p
}

// OpenAIEmbeddingOption configures an OpenAIEmbeddingProvider.
type OpenAIEmbeddingOption func(*OpenAIEmbeddingProvider)

// WithEmbeddingModel sets the embedding model name.
func WithEmbeddingModel(model string) OpenAIEmbeddingOption {
	return func(p *OpenAIEmbeddingProvider) { p.model = model }
}

// WithEmbeddingBaseURL overrides the API base URL (useful for testing).
func WithEmbeddingBaseURL(url string) OpenAIEmbeddingOption {
	return func(p *OpenAIEmbeddingProvider) { p.baseURL = url }
}

// WithEmbeddingHTTPClient sets a custom HTTP client.
func WithEmbeddingHTTPClient(c *http.Client) OpenAIEmbeddingOption {
	return func(p *OpenAIEmbeddingProvider) { p.client = c }
}

// WithEmbeddingDimensions sets the embedding dimensions.
func WithEmbeddingDimensions(dims int) OpenAIEmbeddingOption {
	return func(p *OpenAIEmbeddingProvider) { p.dimensions = dims }
}

// Dimensions returns the vector size produced by this provider.
func (p *OpenAIEmbeddingProvider) Dimensions() int {
	return p.dimensions
}

type embeddingRequest struct {
	Model string `json:"model"`
	Input any    `json:"input"` // string or []string
}

type embeddingResponse struct {
	Data []embeddingData `json:"data"`
}

type embeddingData struct {
	Embedding []float32 `json:"embedding"`
	Index     int       `json:"index"`
}

// Embed generates a vector embedding for a single text input.
func (p *OpenAIEmbeddingProvider) Embed(ctx context.Context, text string) ([]float32, error) {
	text = truncate(text, maxContentChars)
	if text == "" {
		return nil, fmt.Errorf("provider: openai embedding: empty input")
	}

	resp, err := p.callAPI(ctx, text)
	if err != nil {
		return nil, err
	}
	if len(resp.Data) == 0 {
		return nil, fmt.Errorf("provider: openai embedding: empty response")
	}
	return resp.Data[0].Embedding, nil
}

// EmbedBatch generates vector embeddings for multiple text inputs.
func (p *OpenAIEmbeddingProvider) EmbedBatch(ctx context.Context, texts []string) ([][]float32, error) {
	if len(texts) == 0 {
		return nil, nil
	}

	truncated := make([]string, len(texts))
	for i, t := range texts {
		truncated[i] = truncate(t, maxContentChars)
	}

	resp, err := p.callAPI(ctx, truncated)
	if err != nil {
		return nil, err
	}

	results := make([][]float32, len(texts))
	for _, d := range resp.Data {
		if d.Index < len(results) {
			results[d.Index] = d.Embedding
		}
	}
	return results, nil
}

func (p *OpenAIEmbeddingProvider) callAPI(ctx context.Context, input any) (*embeddingResponse, error) {
	body, err := json.Marshal(embeddingRequest{
		Model: p.model,
		Input: input,
	})
	if err != nil {
		return nil, fmt.Errorf("provider: openai embedding: marshal request: %w", err)
	}

	url := p.baseURL + "/embeddings"
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, url, bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("provider: openai embedding: create request: %w", err)
	}
	req.Header.Set("Authorization", "Bearer "+p.apiKey)
	req.Header.Set("Content-Type", "application/json")

	resp, err := p.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("provider: openai embedding: request: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	if resp.StatusCode != http.StatusOK {
		respBody, _ := io.ReadAll(io.LimitReader(resp.Body, 1024))
		return nil, fmt.Errorf("provider: openai embedding: status %d: %s", resp.StatusCode, string(respBody))
	}

	var result embeddingResponse
	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
		return nil, fmt.Errorf("provider: openai embedding: decode response: %w", err)
	}
	return &result, nil
}

func truncate(s string, maxChars int) string {
	if len(s) <= maxChars {
		return s
	}
	slog.Warn("provider: openai embedding: truncating input",
		"original_len", len(s),
		"max_chars", maxChars,
	)
	return s[:maxChars]
}

package provider

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

func TestOpenAIEmbedding_Embed(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			t.Errorf("expected POST, got %s", r.Method)
		}
		if r.URL.Path != "/embeddings" {
			t.Errorf("expected /embeddings, got %s", r.URL.Path)
		}
		if got := r.Header.Get("Authorization"); got != "Bearer test-key" {
			t.Errorf("expected Bearer test-key, got %s", got)
		}

		var req embeddingRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			t.Fatalf("decode request: %v", err)
		}
		if req.Model != "text-embedding-3-small" {
			t.Errorf("expected model text-embedding-3-small, got %s", req.Model)
		}

		resp := embeddingResponse{
			Data: []embeddingData{
				{Embedding: []float32{0.1, 0.2, 0.3}, Index: 0},
			},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	p := NewOpenAIEmbedding("test-key", WithEmbeddingBaseURL(server.URL))

	vec, err := p.Embed(context.Background(), "hello world")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(vec) != 3 {
		t.Fatalf("expected 3 dimensions, got %d", len(vec))
	}
	if vec[0] != 0.1 || vec[1] != 0.2 || vec[2] != 0.3 {
		t.Errorf("unexpected values: %v", vec)
	}
}

func TestOpenAIEmbedding_EmbedBatch(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		resp := embeddingResponse{
			Data: []embeddingData{
				{Embedding: []float32{0.1, 0.2}, Index: 0},
				{Embedding: []float32{0.3, 0.4}, Index: 1},
			},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	p := NewOpenAIEmbedding("test-key", WithEmbeddingBaseURL(server.URL))

	vecs, err := p.EmbedBatch(context.Background(), []string{"hello", "world"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(vecs) != 2 {
		t.Fatalf("expected 2 vectors, got %d", len(vecs))
	}
	if vecs[0][0] != 0.1 {
		t.Errorf("expected first vec[0]=0.1, got %f", vecs[0][0])
	}
	if vecs[1][0] != 0.3 {
		t.Errorf("expected second vec[0]=0.3, got %f", vecs[1][0])
	}
}

func TestOpenAIEmbedding_EmbedBatchEmpty(t *testing.T) {
	p := NewOpenAIEmbedding("test-key")

	vecs, err := p.EmbedBatch(context.Background(), nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if vecs != nil {
		t.Errorf("expected nil for empty batch, got %v", vecs)
	}
}

func TestOpenAIEmbedding_APIError(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusUnauthorized)
		_, _ = w.Write([]byte(`{"error":{"message":"invalid api key"}}`))
	}))
	defer server.Close()

	p := NewOpenAIEmbedding("bad-key", WithEmbeddingBaseURL(server.URL))

	_, err := p.Embed(context.Background(), "hello")
	if err == nil {
		t.Fatal("expected error for 401")
	}
	if !strings.Contains(err.Error(), "status 401") {
		t.Errorf("expected status 401 in error, got: %v", err)
	}
}

func TestOpenAIEmbedding_EmptyResponse(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		resp := embeddingResponse{Data: []embeddingData{}}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	p := NewOpenAIEmbedding("test-key", WithEmbeddingBaseURL(server.URL))

	_, err := p.Embed(context.Background(), "hello")
	if err == nil {
		t.Fatal("expected error for empty response")
	}
	if !strings.Contains(err.Error(), "empty response") {
		t.Errorf("expected 'empty response' in error, got: %v", err)
	}
}

func TestOpenAIEmbedding_EmptyInput(t *testing.T) {
	p := NewOpenAIEmbedding("test-key")

	_, err := p.Embed(context.Background(), "")
	if err == nil {
		t.Fatal("expected error for empty input")
	}
	if !strings.Contains(err.Error(), "empty input") {
		t.Errorf("expected 'empty input' in error, got: %v", err)
	}
}

func TestOpenAIEmbedding_ContextCancelled(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Should not reach here
		t.Error("handler called despite cancelled context")
	}))
	defer server.Close()

	p := NewOpenAIEmbedding("test-key", WithEmbeddingBaseURL(server.URL))

	ctx, cancel := context.WithCancel(context.Background())
	cancel()

	_, err := p.Embed(ctx, "hello")
	if err == nil {
		t.Fatal("expected error for cancelled context")
	}
}

func TestOpenAIEmbedding_Truncation(t *testing.T) {
	var receivedLen int
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var req embeddingRequest
		_ = json.NewDecoder(r.Body).Decode(&req)
		receivedLen = len(req.Input.(string))

		resp := embeddingResponse{
			Data: []embeddingData{{Embedding: []float32{0.1}, Index: 0}},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	p := NewOpenAIEmbedding("test-key", WithEmbeddingBaseURL(server.URL))

	longText := strings.Repeat("a", maxContentChars+1000)
	_, err := p.Embed(context.Background(), longText)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if receivedLen != maxContentChars {
		t.Errorf("expected truncation to %d chars, got %d", maxContentChars, receivedLen)
	}
}

func TestOpenAIEmbedding_CustomModel(t *testing.T) {
	var receivedModel string
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var req embeddingRequest
		_ = json.NewDecoder(r.Body).Decode(&req)
		receivedModel = req.Model

		resp := embeddingResponse{
			Data: []embeddingData{{Embedding: []float32{0.1}, Index: 0}},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	p := NewOpenAIEmbedding("test-key",
		WithEmbeddingBaseURL(server.URL),
		WithEmbeddingModel("text-embedding-3-large"),
	)

	_, err := p.Embed(context.Background(), "hello")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if receivedModel != "text-embedding-3-large" {
		t.Errorf("expected model text-embedding-3-large, got %s", receivedModel)
	}
}

func TestOpenAIEmbedding_Dimensions(t *testing.T) {
	p := NewOpenAIEmbedding("test-key")
	if p.Dimensions() != 1536 {
		t.Errorf("expected 1536, got %d", p.Dimensions())
	}

	p2 := NewOpenAIEmbedding("test-key", WithEmbeddingDimensions(3072))
	if p2.Dimensions() != 3072 {
		t.Errorf("expected 3072, got %d", p2.Dimensions())
	}
}

func TestOpenAIEmbedding_Options(t *testing.T) {
	customClient := &http.Client{}
	p := NewOpenAIEmbedding("key",
		WithEmbeddingModel("custom"),
		WithEmbeddingBaseURL("http://localhost"),
		WithEmbeddingHTTPClient(customClient),
		WithEmbeddingDimensions(768),
	)
	if p.model != "custom" {
		t.Errorf("expected model 'custom', got %q", p.model)
	}
	if p.baseURL != "http://localhost" {
		t.Errorf("expected baseURL 'http://localhost', got %q", p.baseURL)
	}
	if p.client != customClient {
		t.Error("expected custom HTTP client")
	}
	if p.dimensions != 768 {
		t.Errorf("expected dimensions 768, got %d", p.dimensions)
	}
}

