package item

import (
	"context"
	"testing"
)

func TestCaptureBookmarkValidation(t *testing.T) {
	svc := New(nil) // pool is nil — we only test validation, not DB calls

	t.Run("empty URL returns error", func(t *testing.T) {
		_, err := svc.CaptureBookmark(context.TODO(), [16]byte{}, BookmarkInput{URL: ""})
		if err == nil {
			t.Fatal("expected error for empty URL")
		}
	})
}

func TestCaptureNoteValidation(t *testing.T) {
	svc := New(nil)

	t.Run("empty content returns error", func(t *testing.T) {
		_, err := svc.CaptureNote(context.TODO(), [16]byte{}, NoteInput{Content: ""})
		if err == nil {
			t.Fatal("expected error for empty content")
		}
	})
}

func TestBookmarkInputDefaults(t *testing.T) {
	input := BookmarkInput{URL: "https://example.com"}

	// Test that empty source gets default
	if input.Source != "" {
		t.Errorf("expected empty source before default, got %q", input.Source)
	}

	// The service applies defaults — test the logic
	if input.Source == "" {
		input.Source = "api"
	}
	if input.Source != "api" {
		t.Errorf("expected source 'api', got %q", input.Source)
	}

	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}
	if input.Sensitivity != "normal" {
		t.Errorf("expected sensitivity 'normal', got %q", input.Sensitivity)
	}
}

func TestNoteInputDefaults(t *testing.T) {
	input := NoteInput{Content: "hello"}

	if input.Source == "" {
		input.Source = "api"
	}
	if input.Source != "api" {
		t.Errorf("expected source 'api', got %q", input.Source)
	}

	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}
	if input.Sensitivity != "normal" {
		t.Errorf("expected sensitivity 'normal', got %q", input.Sensitivity)
	}
}

func TestSearchEmptyQuery(t *testing.T) {
	svc := New(nil)

	result, err := svc.Search(context.TODO(), [16]byte{}, "", nil, 20, 0.0)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(result.Items) != 0 {
		t.Errorf("expected 0 items for empty query, got %d", len(result.Items))
	}
}

func TestJoinSets(t *testing.T) {
	tests := []struct {
		sets []string
		want string
	}{
		{nil, ""},
		{[]string{}, ""},
		{[]string{"a = $1"}, "a = $1"},
		{[]string{"a = $1", "b = $2"}, "a = $1, b = $2"},
		{[]string{"a = $1", "b = $2", "c = $3"}, "a = $1, b = $2, c = $3"},
	}
	for _, tt := range tests {
		if got := joinSets(tt.sets); got != tt.want {
			t.Errorf("joinSets(%v) = %q, want %q", tt.sets, got, tt.want)
		}
	}
}

